    {"id": "ex_finetune_004", "module": "model_finetuning", "title": "损失计算", "difficulty": "hard", "points": 20,
     "description": "实现语言模型的交叉熵损失计算",
     "starter_code": "import numpy as np\n\ndef softmax(logits):\n    # 实现 softmax\n    pass\n\ndef cross_entropy_loss(logits, targets):\n    # 计算交叉熵损失\n    pass",
     "solution": "import numpy as np\n\ndef softmax(logits):\n    # 数值稳定的 softmax\n    shifted = logits - np.max(logits, axis=-1, keepdims=True)\n    exp_x = np.exp(shifted)\n    return exp_x / exp_x.sum(axis=-1, keepdims=True)\n\ndef cross_entropy_loss(logits, targets):\n    # logits: (batch, vocab) targets: (batch,)\n    probs = softmax(logits)\n    batch_size = logits.shape[0]\n    correct_probs = probs[np.arange(batch_size), targets]\n    loss = -np.mean(np.log(correct_probs + 1e-9))\n    return loss\n\n# 测试\nbatch_size, vocab_size = 4, 100\nlogits = np.random.randn(batch_size, vocab_size)\ntargets = np.random.randint(0, vocab_size, size=batch_size)\nloss = cross_entropy_loss(logits, targets)\nprint(f'Loss: {loss:.4f}')\nprint(f'理论最大损失: {np.log(vocab_size):.4f}')",
     "tags": ["损失函数", "微调"]},

    {"id": "ex_finetune_005", "module": "model_finetuning", "title": "过拟合检测", "difficulty": "medium", "points": 15,
     "description": "实现训练过程监控，检测过拟合",
     "starter_code": "class TrainingMonitor:\n    def __init__(self, patience=3):\n        self.patience = patience\n        self.train_losses = []\n        self.val_losses = []\n    \n    def update(self, train_loss, val_loss):\n        pass\n    \n    def is_overfitting(self):\n        pass\n    \n    def should_stop_early(self):\n        pass",
     "solution": "class TrainingMonitor:\n    def __init__(self, patience=3):\n        self.patience = patience\n        self.train_losses = []\n        self.val_losses = []\n        self.best_val_loss = float('inf')\n        self.no_improve_count = 0\n    \n    def update(self, train_loss, val_loss):\n        self.train_losses.append(train_loss)\n        self.val_losses.append(val_loss)\n        if val_loss < self.best_val_loss:\n            self.best_val_loss = val_loss\n            self.no_improve_count = 0\n        else:\n            self.no_improve_count += 1\n    \n    def is_overfitting(self):\n        if len(self.train_losses) < 2:\n            return False\n        gap = self.val_losses[-1] - self.train_losses[-1]\n        return gap > 0.5\n    \n    def should_stop_early(self):\n        return self.no_improve_count >= self.patience\n    \n    def report(self):\n        if not self.train_losses:\n            return\n        print(f'当前Epoch: {len(self.train_losses)}')\n        print(f'训练Loss: {self.train_losses[-1]:.4f}')\n        print(f'验证Loss: {self.val_losses[-1]:.4f}')\n        print(f'过拟合: {self.is_overfitting()}')\n        print(f'早停: {self.should_stop_early()}')\n\nmonitor = TrainingMonitor(patience=3)\nlosses = [(1.2, 1.3), (0.9, 1.0), (0.6, 1.1), (0.3, 1.4), (0.1, 1.6)]\nfor tl, vl in losses:\n    monitor.update(tl, vl)\n    monitor.report()\n    print()",
     "tags": ["监控", "过拟合"]},

